import React from "react";

function Mission({ goHome, goLogin }) {
  return (
    <div className="page">
      <h1>Our Mission</h1>
      <p>This is the Mission page.</p>
      <button onClick={goHome}>Back to Home</button>
      <button onClick={goLogin}>Logout / Login</button>
    </div>
  );
}

export default Mission;
